	"source": "import { Body, Container, Head, Heading, Html, Img, Link, Section, Text } from 'jsx-email';\n\ninterface PlaidVerifyIdentityEmailProps {\n  validationCode?: string;\n}\n\nconst main = {\n  backgroundColor: '#ffffff',\n  fontFamily: 'HelveticaNeue,Helvetica,Arial,sans-serif'\n};\n\nconst container = {\n  backgroundColor: '#ffffff',\n  border: '1px solid #eee',\n  borderRadius: '5px',\n  boxShadow: '0 5px 10px rgba(20,50,70,.2)',\n  marginTop: '20px',\n  width: '360px',\n  margin: '0 auto',\n  padding: '68px 0 130px'\n};\n\nconst logo = {\n  margin: '0 auto'\n};\n\nconst tertiary = {\n  color: '#0a85ea',\n  fontSize: '11px',\n  fontWeight: 700,\n  fontFamily: 'HelveticaNeue,Helvetica,Arial,sans-serif',\n  height: '16px',\n  letterSpacing: '0',\n  lineHeight: '16px',\n  margin: '16px 8px 8px 8px',\n  textTransform: 'uppercase' as const,\n  textAlign: 'center' as const\n};\n\nconst secondary = {\n  color: '#000',\n  display: 'inline-block',\n  fontFamily: 'HelveticaNeue-Medium,Helvetica,Arial,sans-serif',\n  fontSize: '20px',\n  fontWeight: 500,\n  lineHeight: '24px',\n  marginBottom: '0',\n  marginTop: '0',\n  textAlign: 'center' as const\n};\n\nconst codeContainer = {\n  background: 'rgba(0,0,0,.05)',\n  borderRadius: '4px',\n  margin: '16px auto 14px',\n  verticalAlign: 'middle',\n  width: '280px'\n};\n\nconst code = {\n  color: '#000',\n  display: 'inline-block',\n  fontFamily: 'HelveticaNeue-Bold',\n  fontSize: '32px',\n  fontWeight: 700,\n  letterSpacing: '6px',\n  lineHeight: '40px',\n  paddingBottom: '8px',\n  paddingTop: '8px',\n  margin: '0 auto',\n  width: '100%',\n  textAlign: 'center' as const\n};\n\nconst paragraph = {\n  color: '#444',\n  fontSize: '15px',\n  fontFamily: 'HelveticaNeue,Helvetica,Arial,sans-serif',\n  letterSpacing: '0',\n  lineHeight: '23px',\n  padding: '0 40px',\n  margin: '0',\n  textAlign: 'center' as const\n};\n\nconst link = {\n  color: '#444',\n  textDecoration: 'underline'\n};\n\nconst footer = {\n  color: '#000',\n  fontSize: '12px',\n  fontWeight: 800,\n  letterSpacing: '0',\n  lineHeight: '23px',\n  margin: '0',\n  marginTop: '20px',\n  fontFamily: 'HelveticaNeue,Helvetica,Arial,sans-serif',\n  textAlign: 'center' as const,\n  textTransform: 'uppercase' as const\n};\n\nconst baseUrl = import.meta.isJsxEmailPreview ? '/static/' : 'https://jsx.email/assets/samples/';\n\nexport const previewProps = {\n  validationCode: '144833'\n} as PlaidVerifyIdentityEmailProps;\n\nexport const templateName = 'Plaid Verify Identity';\n\nexport const Template = ({ validationCode }: PlaidVerifyIdentityEmailProps) => (\n  <Html>\n    <Head />\n    <Body style={main}>\n      <Container style={container}>\n        <Img src={`${baseUrl}plaid-logo.png`} width=\"212\" height=\"88\" alt=\"Plaid\" style={logo} />\n        <Text style={tertiary}>Verify Your Identity</Text>\n        <Heading style={secondary}>Enter the following code to finish linking Venmo.</Heading>\n        <Section style={codeContainer}>\n          <Text style={code}>{validationCode}</Text>\n        </Section>\n        <Text style={paragraph}>Not expecting this email?</Text>\n        <Text style={paragraph}>\n          Contact{' '}\n          <Link href=\"mailto:login@plaid.com\" style={link}>\n            login@plaid.com\n          </Link>{' '}\n          if you did not request this code.\n        </Text>\n      </Container>\n      <Text style={footer}>Securely powered by Plaid.</Text>\n    </Body>\n  </Html>\n);\n",
